+    // Report the transform from base_link to gimbal here.
+    node_declare_and_watch_parameter(
+      "tf.send", false, [&](const rclcpp::Parameter & p) {
+        tf_send = p.as_bool();
+      });
+    node_declare_and_watch_parameter(
+      "tf.frame_id", "base_link_frd", [&](const rclcpp::Parameter & p) {
+        tf_frame_id = p.as_string();
