+    HilControlsPlugin() :
+        hil_controls_nh("~hil_controls"),
+        uas(nullptr)
+    { };
+
+    void initialize(UAS &uas_)
+    {
+        uas = &uas_;
+
+        hil_controls_pub = hil_controls_nh.advertise<mavros_msgs::HilControls>("hil_controls", 10);
+    };
+
